1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - nextGeneration", () => {
6	  it("should return an empty array for an empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should let a single cell die (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should let two neighboring cells die, each having only 1 neighbor (underpopulation)", () => {
13	    expect(
14	      nextGeneration([
15	        [0, 1],
16	        [1, 1],
17	      ]),
18	    ).toEqual([]);
19	  });
20	  it("should let a live cell with 3 live neighbors survive (survival)", () => {
21	    // Gen 0:        Gen 1 (at minimum):
22	    //  ###           (1,1) survives — it has exactly
23	    //  .#.           3 live neighbors: (0,0),(1,0),(2,0)
24	    expect(
25	      nextGeneration([
26	        [0, 0],
27	        [1, 0],
28	        [2, 0],
29	        [1, 1],
30	      ]),
31	    ).toContainEqual([1, 1]);
32	  });
33	  it("should let a live cell with 4 live neighbors die (overpopulation)", () => {
34	    // Gen 0:        Center (1,1) has exactly 4 live
35	    //  #.#          neighbors: (0,0),(2,0),(0,2),(2,2)
36	    //  .#.          → dies of overpopulation
37	    //  #.#
38	    expect(
39	      nextGeneration([
40	        [1, 1],
41	        [0, 0],
42	        [2, 0],
43	        [0, 2],
44	        [2, 2],
45	      ]),
46	    ).not.toContainEqual([1, 1]);
47	  });
48	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
49	    // Gen 0:        Gen 1:
50	    //  ##.           ##.
51	    //  #..     →     ##.
52	    //  ...           ...
53	    // Dead cell (1,1) has exactly 3 live neighbors: (0,0),(1,0),(0,1)
54	    expect(
55	      nextGeneration([
56	        [0, 0],
57	        [1, 0],
58	        [0, 1],
59	      ]),
60	    ).toContainEqual([1, 1]);
61	  });
62	  it.todo(
63	    "should oscillate a blinker from vertical to horizontal, producing negative coordinates",
64	  );
65	  it.todo("should keep a block (still life) unchanged");
66	  // NOT: input validation, duplicate-cell handling, performance,
67	  // other patterns (glider, toad, etc.) - not in the spec
68	});
