1	// game-of-life.ts
2	export type Cell = [number, number];
3	
4	const isSameCell = ([x, y]: Cell, [ox, oy]: Cell): boolean =>
5	  x === ox && y === oy;
6	
7	const isNeighborOf = (cell: Cell, other: Cell): boolean =>
8	  Math.abs(other[0] - cell[0]) <= 1 &&
9	  Math.abs(other[1] - cell[1]) <= 1 &&
10	  !isSameCell(cell, other);
11	
12	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
13	  liveCells.filter((other) => isNeighborOf(cell, other)).length;
14	
15	const offsets = [-1, 0, 1];
16	
17	const neighborsOf = (cell: Cell): Cell[] =>
18	  offsets
19	    .flatMap((dx) => offsets.map((dy): Cell => [cell[0] + dx, cell[1] + dy]))
20	    .filter((candidate) => !isSameCell(candidate, cell));
21	
22	const contains = (cells: Cell[], cell: Cell): boolean =>
23	  cells.some((other) => isSameCell(other, cell));
24	
25	const unique = (cells: Cell[]): Cell[] =>
26	  cells.filter((cell, index) => !contains(cells.slice(0, index), cell));
27	
28	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
29	  const survivors = liveCells.filter(
30	    (cell) => countLiveNeighbors(cell, liveCells) === 3,
31	  );
32	  const born = unique(liveCells.flatMap(neighborsOf))
33	    .filter((cell) => !contains(liveCells, cell))
34	    .filter((cell) => countLiveNeighbors(cell, liveCells) === 3);
35	  return [...survivors, ...born];
36	};
