it("should oscillate a blinker from vertical to horizontal, producing negative coordinates", () => {
  // Gen 0 (vertical):   Gen 1 (horizontal):
  //  .#.                 ...
  //  .#.          →      ###   ← includes negative x at (-1,1)
  //  .#.                 ...
  expect(
    sorted(
      nextGeneration([
        [0, 0],
        [0, 1],
        [0, 2],
      ]),
    ),
  ).toEqual(
    sorted([
      [-1, 1],
      [0, 1],
      [1, 1],
    ]),
  );
});
